function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: Map<number, Map<number, number>> = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, new Map());
        }
        graph.get(u)!.set(v, cost);
    }

    // Use Dijkstra's algorithm to find the maximum minimum edge cost path
    // We'll use a max-heap to prioritize paths with higher minimum edge cost
    // We'll store tuples of (current node, current minimum edge cost, total cost so far)
    const maxHeap: [number, number, number][] = [];
    // We'll use a priority queue to explore paths with higher minimum edge cost first
    // We'll also use a dictionary to keep track of the best minimum edge cost for each node
    const minEdgeCosts: Map<number, number> = new Map();

    // Start from node 0
    if (online[0]) {
        maxHeap.push([0, Number.MAX_VALUE, 0]);
        minEdgeCosts.set(0, Number.MAX_VALUE);
    }

    // Use a priority queue to explore paths
    while (maxHeap.length > 0) {
        // Extract the path with the highest minimum edge cost
        const [u, minEdge, totalCost] = maxHeap.pop()!;
        if (u === n - 1) {
            return minEdge;
        }

        // If we've already found a better path to this node, skip it
        if (minEdge < minEdgeCosts.get(u)!) {
            continue;
        }

        // Explore neighbors
        if (graph.has(u)) {
            for (const [v, cost] of graph.get(u)!.entries()) {
                // Check if the neighbor is online
                if (online[v]) {
                    // Calculate the new minimum edge cost
                    const newMinEdge = Math.min(minEdge, cost);
                    // Calculate the new total cost
                    const newTotalCost = totalCost + cost;

                    // If the new total cost is within k and we haven't found a better path to v
                    if (newTotalCost <= k && (newMinEdge > minEdgeCosts.get(v) || !minEdgeCosts.has(v))) {
                        minEdgeCosts.set(v, newMinEdge);
                        maxHeap.push([v, newMinEdge, newTotalCost]);
                    }
                }
            }
        }
    }

    // If no valid path is found
    return -1;
}

